// Gerado automaticamente — não editar à mão
module.exports = {
  "admin.html": "<!DOCTYPE html>\r\n<html lang=\"pt-BR\">\r\n<head>\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>Admin - Pedidos de Ativação</title>\r\n  <link rel=\"stylesheet\" href=\"/styles.css\">\r\n</head>\r\n<body>\r\n  <div id=\"login-screen\" class=\"screen\">\r\n    <div class=\"login-card\">\r\n      <div class=\"logo\">Admin Panel</div>\r\n      <p class=\"subtitle\">Pedidos de ativação</p>\r\n      <form id=\"login-form\">\r\n        <input type=\"password\" id=\"password\" placeholder=\"Senha\" required>\r\n        <button type=\"submit\" class=\"btn-primary full\">Entrar</button>\r\n      </form>\r\n      <p id=\"login-error\" class=\"error hidden\"></p>\r\n    </div>\r\n  </div>\r\n\r\n  <div id=\"app\" class=\"layout hidden\">\r\n    <aside class=\"sidebar\">\r\n      <div class=\"sidebar-brand\">\r\n        <strong>Pedidos</strong>\r\n        <span>ADMIN</span>\r\n      </div>\r\n      <nav class=\"sidebar-nav\">\r\n        <button class=\"nav-item active\" data-tab=\"pending\">⏳ Pendentes</button>\r\n        <button class=\"nav-item\" data-tab=\"approved\">✓ Aprovados</button>\r\n        <button class=\"nav-item\" data-tab=\"rejected\">✕ Recusados</button>\r\n        <button class=\"nav-item\" data-tab=\"activations\">📋 Ativados</button>\r\n      </nav>\r\n      <a href=\"/\" class=\"back-link\">← Voltar ao site</a>\r\n    </aside>\r\n\r\n    <main class=\"main\">\r\n      <header class=\"page-header\">\r\n        <div>\r\n          <h1 id=\"page-title\">Pedidos pendentes</h1>\r\n          <p id=\"page-sub\">Aprove ou recuse os pedidos dos clientes</p>\r\n        </div>\r\n        <div class=\"header-actions\">\r\n          <button id=\"refresh-btn\" class=\"tool-btn\">Atualizar</button>\r\n          <button id=\"sound-toggle\" class=\"tool-btn sound-on\" type=\"button\" title=\"Ativar/desativar som de notificação\">🔔 Som ligado</button>\r\n        </div>\r\n      </header>\r\n\r\n      <div class=\"stats-row\">\r\n        <div class=\"stat-card\"><span>Pendentes</span><strong id=\"stat-pending\">0</strong></div>\r\n        <div class=\"stat-card green\"><span>Aprovados</span><strong id=\"stat-approved\">0</strong></div>\r\n        <div class=\"stat-card red\"><span>Recusados</span><strong id=\"stat-rejected\">0</strong></div>\r\n        <div class=\"stat-card\"><span>Total</span><strong id=\"stat-total\">0</strong></div>\r\n      </div>\r\n\r\n      <div class=\"card table-card\">\r\n        <div class=\"table-wrap\">\r\n          <table>\r\n            <thead id=\"table-head\"></thead>\r\n            <tbody id=\"table-body\"></tbody>\r\n          </table>\r\n        </div>\r\n      </div>\r\n    </main>\r\n  </div>\r\n\r\n  <div id=\"toast\" class=\"toast hidden\"></div>\r\n  <script src=\"/admin.js\"></script>\r\n</body>\r\n</html>\r\n",
  "admin.js": "let token = localStorage.getItem('adminToken');\r\nlet currentTab = 'pending';\r\nlet knownPendingIds = new Set();\r\nlet notificationsReady = false;\r\nlet pollTimer = null;\r\n\r\nconst SOUND_ENABLED_KEY = 'adminSoundEnabled';\r\nconst POLL_INTERVAL_MS = 5000;\r\n\r\nconst $ = (s) => document.querySelector(s);\r\nconst $$ = (s) => document.querySelectorAll(s);\r\n\r\nconst titles = {\r\n  pending: ['Pedidos pendentes', 'Aprove ou recuse os pedidos dos clientes'],\r\n  approved: ['Aprovados', 'Pedidos já ativados'],\r\n  rejected: ['Recusados', 'Pedidos negados'],\r\n  activations: ['Contas ativadas', 'Histórico de ativações com validade']\r\n};\r\n\r\nfunction isSoundEnabled() {\r\n  return localStorage.getItem(SOUND_ENABLED_KEY) !== 'false';\r\n}\r\n\r\nfunction updateSoundToggle() {\r\n  const btn = $('#sound-toggle');\r\n  if (!btn) return;\r\n  const on = isSoundEnabled();\r\n  btn.textContent = on ? '🔔 Som ligado' : '🔕 Som desligado';\r\n  btn.classList.toggle('sound-on', on);\r\n  btn.classList.toggle('sound-off', !on);\r\n}\r\n\r\nfunction playNotificationSound() {\r\n  if (!isSoundEnabled()) return;\r\n\r\n  try {\r\n    const ctx = new (window.AudioContext || window.webkitAudioContext)();\r\n    [0, 0.18].forEach((delay) => {\r\n      const osc = ctx.createOscillator();\r\n      const gain = ctx.createGain();\r\n      osc.type = 'sine';\r\n      osc.frequency.value = delay ? 1100 : 880;\r\n      gain.gain.setValueAtTime(0.0001, ctx.currentTime + delay);\r\n      gain.gain.exponentialRampToValueAtTime(0.25, ctx.currentTime + delay + 0.02);\r\n      gain.gain.exponentialRampToValueAtTime(0.0001, ctx.currentTime + delay + 0.35);\r\n      osc.connect(gain);\r\n      gain.connect(ctx.destination);\r\n      osc.start(ctx.currentTime + delay);\r\n      osc.stop(ctx.currentTime + delay + 0.4);\r\n    });\r\n  } catch {\r\n    // Alguns navegadores bloqueiam áudio sem interação do usuário.\r\n  }\r\n}\r\n\r\nfunction showDesktopNotification(request) {\r\n  if (!('Notification' in window) || Notification.permission !== 'granted') return;\r\n\r\n  const parts = [`ID ${request.uid}`];\r\n  if (request.discord_nick) parts.push(`Discord: ${request.discord_nick}`);\r\n  if (request.plan_label) parts.push(`plano ${request.plan_label}`);\r\n\r\n  new Notification('Novo pedido de ativação', { body: parts.join(' — ') });\r\n}\r\n\r\nfunction showToast(text, isError = false) {\r\n  const t = $('#toast');\r\n  t.textContent = text;\r\n  t.style.borderColor = isError ? 'var(--red)' : 'var(--green)';\r\n  t.classList.remove('hidden');\r\n  setTimeout(() => t.classList.add('hidden'), 3500);\r\n}\r\n\r\nasync function api(path, opts = {}) {\r\n  const headers = { 'Content-Type': 'application/json', ...(opts.headers || {}) };\r\n  if (token) headers['X-Admin-Token'] = token;\r\n  const res = await fetch(path, { ...opts, headers });\r\n  const data = await res.json().catch(() => ({}));\r\n  if (res.status === 401) { logout(); throw new Error('Sessão expirada'); }\r\n  if (!res.ok) throw new Error(data.message || 'Erro');\r\n  return data;\r\n}\r\n\r\nfunction stopNotificationWatcher() {\r\n  if (pollTimer) {\r\n    clearInterval(pollTimer);\r\n    pollTimer = null;\r\n  }\r\n  notificationsReady = false;\r\n  knownPendingIds = new Set();\r\n}\r\n\r\nfunction startNotificationWatcher() {\r\n  stopNotificationWatcher();\r\n  pollTimer = setInterval(checkNewRequests, POLL_INTERVAL_MS);\r\n  checkNewRequests();\r\n}\r\n\r\nasync function checkNewRequests() {\r\n  if (!token || $('#app').classList.contains('hidden')) return;\r\n\r\n  try {\r\n    const { data } = await api('/api/admin/requests?status=pending');\r\n    const ids = new Set(data.map((r) => r.id));\r\n\r\n    if (!notificationsReady) {\r\n      knownPendingIds = ids;\r\n      notificationsReady = true;\r\n      return;\r\n    }\r\n\r\n    const newRequests = data.filter((r) => !knownPendingIds.has(r.id));\r\n    if (newRequests.length > 0) {\r\n      playNotificationSound();\r\n      const label = newRequests.map((r) => {\r\n        const nick = r.discord_nick ? ` (${r.discord_nick})` : '';\r\n        return `${r.uid}${nick}`;\r\n      }).join(', ');\r\n      showToast(`Novo pedido: ${label}`);\r\n      showDesktopNotification(newRequests[0]);\r\n\r\n      if (currentTab === 'pending') {\r\n        await Promise.all([loadStats(), loadTable()]);\r\n      } else {\r\n        await loadStats();\r\n      }\r\n    }\r\n\r\n    knownPendingIds = ids;\r\n  } catch {\r\n    // Ignora falhas temporárias de rede durante o polling.\r\n  }\r\n}\r\n\r\nfunction logout() {\r\n  stopNotificationWatcher();\r\n  token = null;\r\n  localStorage.removeItem('adminToken');\r\n  $('#app').classList.add('hidden');\r\n  $('#login-screen').classList.remove('hidden');\r\n}\r\n\r\nfunction formatDate(d) {\r\n  if (!d) return '—';\r\n  return new Date(d.replace(' ', 'T') + 'Z').toLocaleString('pt-BR');\r\n}\r\n\r\nfunction planBadge(plan, label) {\r\n  return `<span class=\"badge ${plan}\">${label || plan}</span>`;\r\n}\r\n\r\nasync function loadStats() {\r\n  const { data } = await api('/api/admin/stats');\r\n  $('#stat-pending').textContent = data.pending;\r\n  $('#stat-approved').textContent = data.approved;\r\n  $('#stat-rejected').textContent = data.rejected;\r\n  $('#stat-total').textContent = data.total;\r\n}\r\n\r\nasync function loadTable() {\r\n  const head = $('#table-head');\r\n  const body = $('#table-body');\r\n  const [t1, t2] = titles[currentTab];\r\n  $('#page-title').textContent = t1;\r\n  $('#page-sub').textContent = t2;\r\n\r\n  if (currentTab === 'activations') {\r\n    head.innerHTML = `<tr><th>ID</th><th>Discord</th><th>Plano</th><th>Ativado em</th><th>Expira em</th></tr>`;\r\n    const { data } = await api('/api/admin/activations');\r\n    if (!data.length) {\r\n      body.innerHTML = '<tr class=\"empty-row\"><td colspan=\"5\">Nenhuma ativação ainda</td></tr>';\r\n      return;\r\n    }\r\n    body.innerHTML = data.map((r) => `\r\n      <tr>\r\n        <td><strong>${r.uid}</strong></td>\r\n        <td>${r.discord_nick || '—'}</td>\r\n        <td>${planBadge(r.plan, r.plan_label)}</td>\r\n        <td>${formatDate(r.approved_at)}</td>\r\n        <td>${formatDate(r.expires_at)}</td>\r\n      </tr>\r\n    `).join('');\r\n    return;\r\n  }\r\n\r\n  head.innerHTML = `<tr><th>ID</th><th>Discord</th><th>Plano</th><th>Status</th><th>Enviado em</th><th>Ações</th></tr>`;\r\n  const { data } = await api(`/api/admin/requests?status=${currentTab}`);\r\n  if (!data.length) {\r\n    body.innerHTML = `<tr class=\"empty-row\"><td colspan=\"6\">Nenhum pedido ${currentTab === 'pending' ? 'pendente' : ''}</td></tr>`;\r\n    return;\r\n  }\r\n\r\n  body.innerHTML = data.map((r) => `\r\n    <tr>\r\n      <td><strong>${r.uid}</strong></td>\r\n      <td>${r.discord_nick || '—'}</td>\r\n      <td>${planBadge(r.plan, r.plan_label)}</td>\r\n      <td><span class=\"badge ${r.status}\">${r.status === 'pending' ? 'Pendente' : r.status === 'approved' ? 'Aprovado' : 'Recusado'}</span></td>\r\n      <td>${formatDate(r.created_at)}</td>\r\n      <td class=\"actions\">\r\n        ${r.status === 'pending' ? `\r\n          <button class=\"btn-approve\" onclick=\"approve('${r.id}')\">Ativar</button>\r\n          <button class=\"btn-reject\" onclick=\"reject('${r.id}')\">Recusar</button>\r\n        ` : ''}\r\n        <button class=\"btn-delete\" onclick=\"removeReq('${r.id}')\">Excluir</button>\r\n      </td>\r\n    </tr>\r\n  `).join('');\r\n}\r\n\r\nasync function refresh() {\r\n  await Promise.all([loadStats(), loadTable()]);\r\n  const { data } = await api('/api/admin/requests?status=pending');\r\n  knownPendingIds = new Set(data.map((r) => r.id));\r\n  notificationsReady = true;\r\n}\r\n\r\nwindow.approve = async (id) => {\r\n  try {\r\n    const res = await api(`/api/admin/requests/${id}/approve`, { method: 'POST' });\r\n    const legacy = res.legacy_sync;\r\n    if (legacy?.synced) showToast('Ativado aqui e no servidor antigo ✓');\r\n    else if (legacy && !legacy.skipped) showToast('Aprovado aqui, falhou no servidor antigo', true);\r\n    else showToast(res.message || 'Pedido aprovado!');\r\n    refresh();\r\n  } catch (e) { showToast(e.message, true); }\r\n};\r\n\r\nwindow.reject = async (id) => {\r\n  if (!confirm('Recusar este pedido?')) return;\r\n  try {\r\n    await api(`/api/admin/requests/${id}/reject`, { method: 'POST' });\r\n    showToast('Pedido recusado');\r\n    refresh();\r\n  } catch (e) { showToast(e.message, true); }\r\n};\r\n\r\nwindow.removeReq = async (id) => {\r\n  if (!confirm('Excluir este registro?')) return;\r\n  try {\r\n    await api(`/api/admin/requests/${id}`, { method: 'DELETE' });\r\n    showToast('Excluído');\r\n    refresh();\r\n  } catch (e) { showToast(e.message, true); }\r\n};\r\n\r\nasync function enterAdminPanel() {\r\n  $('#login-screen').classList.add('hidden');\r\n  $('#app').classList.remove('hidden');\r\n  updateSoundToggle();\r\n  playNotificationSound();\r\n\r\n  if ('Notification' in window && Notification.permission === 'default') {\r\n    Notification.requestPermission();\r\n  }\r\n\r\n  await refresh();\r\n  startNotificationWatcher();\r\n}\r\n\r\n$('#login-form').addEventListener('submit', async (e) => {\r\n  e.preventDefault();\r\n  try {\r\n    const { token: t } = await api('/api/admin/login', {\r\n      method: 'POST',\r\n      body: JSON.stringify({ password: $('#password').value })\r\n    });\r\n    token = t;\r\n    localStorage.setItem('adminToken', t);\r\n    await enterAdminPanel();\r\n  } catch (err) {\r\n    $('#login-error').textContent = err.message;\r\n    $('#login-error').classList.remove('hidden');\r\n  }\r\n});\r\n\r\n$$('.nav-item').forEach((btn) => {\r\n  btn.addEventListener('click', () => {\r\n    $$('.nav-item').forEach((b) => b.classList.remove('active'));\r\n    btn.classList.add('active');\r\n    currentTab = btn.dataset.tab;\r\n    loadTable();\r\n  });\r\n});\r\n\r\n$('#refresh-btn').onclick = refresh;\r\n\r\n$('#sound-toggle').onclick = () => {\r\n  localStorage.setItem(SOUND_ENABLED_KEY, isSoundEnabled() ? 'false' : 'true');\r\n  updateSoundToggle();\r\n  if (isSoundEnabled()) playNotificationSound();\r\n};\r\n\r\nif (token) {\r\n  enterAdminPanel().catch(logout);\r\n}\r\n",
  "index.html": "<!DOCTYPE html>\r\n<html lang=\"pt-BR\">\r\n<head>\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>Ativação de Conta</title>\r\n  <link rel=\"stylesheet\" href=\"/styles.css\">\r\n</head>\r\n<body class=\"public-page\">\r\n  <div class=\"public-wrap\">\r\n    <div class=\"public-card\">\r\n      <div class=\"public-logo\">⚡ Ativação</div>\r\n      <h1>Solicitar ativação</h1>\r\n      <p class=\"public-sub\">Envie seu ID, nick do Discord e o plano que você comprou.</p>\r\n\r\n      <form id=\"request-form\">\r\n        <label>Seu ID (Account ID)</label>\r\n        <input type=\"text\" id=\"uid\" placeholder=\"Ex: 632825155\" required inputmode=\"numeric\">\r\n\r\n        <label>Nick do Discord</label>\r\n        <input type=\"text\" id=\"discord-nick\" placeholder=\"Ex: seuusuario\" required maxlength=\"64\" autocomplete=\"username\">\r\n\r\n        <label>Plano comprado</label>\r\n        <div class=\"plan-options plan-options-3\">\r\n          <label class=\"plan-option\">\r\n            <input type=\"radio\" name=\"plan\" value=\"diario\">\r\n            <span class=\"plan-box\">\r\n              <strong>Diário</strong>\r\n              <small>1 dia de acesso</small>\r\n            </span>\r\n          </label>\r\n          <label class=\"plan-option\">\r\n            <input type=\"radio\" name=\"plan\" value=\"semanal\" checked>\r\n            <span class=\"plan-box\">\r\n              <strong>Semanal</strong>\r\n              <small>7 dias de acesso</small>\r\n            </span>\r\n          </label>\r\n          <label class=\"plan-option\">\r\n            <input type=\"radio\" name=\"plan\" value=\"mensal\">\r\n            <span class=\"plan-box\">\r\n              <strong>Mensal</strong>\r\n              <small>30 dias de acesso</small>\r\n            </span>\r\n          </label>\r\n        </div>\r\n\r\n        <button type=\"submit\" class=\"btn-primary full\">Enviar pedido</button>\r\n      </form>\r\n\r\n      <p id=\"form-msg\" class=\"form-msg hidden\"></p>\r\n    </div>\r\n\r\n    <p class=\"admin-link\"><a href=\"/admin\">Área do admin</a></p>\r\n  </div>\r\n  <script src=\"/request.js\"></script>\r\n</body>\r\n</html>\r\n",
  "request.js": "const form = document.getElementById('request-form');\r\nconst msg = document.getElementById('form-msg');\r\n\r\nform.addEventListener('submit', async (e) => {\r\n  e.preventDefault();\r\n  msg.classList.add('hidden');\r\n\r\n  const uid = document.getElementById('uid').value.trim();\r\n  const discord_nick = document.getElementById('discord-nick').value.trim();\r\n  const plan = document.querySelector('input[name=\"plan\"]:checked')?.value;\r\n\r\n  try {\r\n    const res = await fetch('/api/request', {\r\n      method: 'POST',\r\n      headers: { 'Content-Type': 'application/json' },\r\n      body: JSON.stringify({ uid, discord_nick, plan })\r\n    });\r\n    const data = await res.json();\r\n\r\n    msg.classList.remove('hidden', 'ok', 'err');\r\n    if (data.success) {\r\n      msg.textContent = data.message;\r\n      msg.classList.add('ok');\r\n      form.reset();\r\n      document.querySelector('input[value=\"semanal\"]').checked = true;\r\n    } else {\r\n      msg.textContent = data.message;\r\n      msg.classList.add('err');\r\n    }\r\n  } catch {\r\n    msg.classList.remove('hidden', 'ok');\r\n    msg.textContent = 'Erro ao enviar. Tente novamente.';\r\n    msg.classList.add('err');\r\n  }\r\n});\r\n",
  "styles.css": ":root {\r\n  --bg: #0a0c10;\r\n  --surface: #13161d;\r\n  --surface-2: #1a1e28;\r\n  --border: #252a36;\r\n  --text: #f0f2f6;\r\n  --muted: #7d8596;\r\n  --green: #00e676;\r\n  --green-dim: #00c853;\r\n  --red: #ff5252;\r\n  --radius: 14px;\r\n}\r\n\r\n* { box-sizing: border-box; margin: 0; padding: 0; }\r\n\r\nbody {\r\n  font-family: 'Segoe UI', Inter, system-ui, sans-serif;\r\n  background: var(--bg);\r\n  color: var(--text);\r\n  min-height: 100vh;\r\n}\r\n\r\n.hidden { display: none !important; }\r\n\r\ninput, select, textarea {\r\n  width: 100%;\r\n  background: var(--surface-2);\r\n  border: 1px solid var(--border);\r\n  color: var(--text);\r\n  border-radius: 10px;\r\n  padding: .85rem 1rem;\r\n  font-size: .95rem;\r\n}\r\n\r\ninput:focus { outline: none; border-color: var(--green); }\r\n\r\n.btn-primary {\r\n  background: var(--green);\r\n  color: #000;\r\n  border: none;\r\n  border-radius: 10px;\r\n  padding: .9rem 1.25rem;\r\n  font-weight: 700;\r\n  cursor: pointer;\r\n  font-size: .95rem;\r\n}\r\n\r\n.btn-primary:hover { background: var(--green-dim); }\r\n.btn-primary.full { width: 100%; }\r\n\r\n/* Página pública */\r\n.public-page {\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  padding: 1.5rem;\r\n  background: radial-gradient(ellipse at top, #0f1a14 0%, var(--bg) 60%);\r\n}\r\n\r\n.public-wrap { width: 100%; max-width: 440px; }\r\n\r\n.public-card {\r\n  background: var(--surface);\r\n  border: 1px solid var(--border);\r\n  border-radius: var(--radius);\r\n  padding: 2rem;\r\n}\r\n\r\n.public-logo {\r\n  color: var(--green);\r\n  font-weight: 700;\r\n  font-size: .9rem;\r\n  margin-bottom: .5rem;\r\n}\r\n\r\n.public-card h1 { font-size: 1.5rem; margin-bottom: .35rem; }\r\n\r\n.public-sub {\r\n  color: var(--muted);\r\n  font-size: .9rem;\r\n  margin-bottom: 1.5rem;\r\n  line-height: 1.5;\r\n}\r\n\r\n#request-form label {\r\n  display: block;\r\n  font-size: .85rem;\r\n  color: var(--muted);\r\n  margin: 1rem 0 .4rem;\r\n}\r\n\r\n#request-form label:first-of-type { margin-top: 0; }\r\n\r\n.plan-options {\r\n  display: grid;\r\n  grid-template-columns: 1fr 1fr;\r\n  gap: .75rem;\r\n}\r\n\r\n.plan-options-3 {\r\n  grid-template-columns: 1fr 1fr 1fr;\r\n}\r\n\r\n.plan-option input { display: none; }\r\n\r\n.plan-box {\r\n  display: block;\r\n  background: var(--surface-2);\r\n  border: 2px solid var(--border);\r\n  border-radius: 10px;\r\n  padding: 1rem;\r\n  cursor: pointer;\r\n  text-align: center;\r\n  transition: .15s;\r\n}\r\n\r\n.plan-box strong { display: block; margin-bottom: .2rem; }\r\n.plan-box small { color: var(--muted); font-size: .75rem; }\r\n\r\n.plan-option input:checked + .plan-box {\r\n  border-color: var(--green);\r\n  background: rgba(0, 230, 118, 0.08);\r\n}\r\n\r\n#request-form button { margin-top: 1.25rem; }\r\n\r\n.form-msg {\r\n  margin-top: 1rem;\r\n  padding: .85rem;\r\n  border-radius: 8px;\r\n  font-size: .9rem;\r\n  text-align: center;\r\n}\r\n\r\n.form-msg.ok { background: rgba(0,230,118,.12); color: var(--green); border: 1px solid rgba(0,230,118,.3); }\r\n.form-msg.err { background: rgba(255,82,82,.12); color: var(--red); border: 1px solid rgba(255,82,82,.3); }\r\n\r\n.admin-link {\r\n  text-align: center;\r\n  margin-top: 1.25rem;\r\n  font-size: .85rem;\r\n}\r\n\r\n.admin-link a { color: var(--muted); }\r\n\r\n/* Admin */\r\n.screen { min-height: 100vh; }\r\n\r\n.login-card {\r\n  max-width: 380px;\r\n  margin: 12vh auto;\r\n  background: var(--surface);\r\n  border: 1px solid var(--border);\r\n  border-radius: var(--radius);\r\n  padding: 2rem;\r\n}\r\n\r\n.logo { font-size: 1.4rem; font-weight: 700; color: var(--green); text-align: center; }\r\n.subtitle { text-align: center; color: var(--muted); margin: .4rem 0 1.25rem; font-size: .9rem; }\r\n#login-form { display: grid; gap: .75rem; }\r\n.error { color: var(--red); text-align: center; margin-top: .75rem; font-size: .9rem; }\r\n\r\n.layout {\r\n  display: grid;\r\n  grid-template-columns: 220px 1fr;\r\n  min-height: 100vh;\r\n}\r\n\r\n.sidebar {\r\n  background: #0e1015;\r\n  border-right: 1px solid var(--border);\r\n  padding: 1.25rem 1rem;\r\n  display: flex;\r\n  flex-direction: column;\r\n}\r\n\r\n.sidebar-brand {\r\n  padding: .5rem .75rem 1.25rem;\r\n  border-bottom: 1px solid var(--border);\r\n  margin-bottom: 1rem;\r\n}\r\n\r\n.sidebar-brand strong { display: block; color: var(--green); }\r\n.sidebar-brand span { font-size: .65rem; color: var(--muted); letter-spacing: .06em; }\r\n\r\n.sidebar-nav { display: flex; flex-direction: column; gap: .25rem; flex: 1; }\r\n\r\n.nav-item {\r\n  background: none;\r\n  border: none;\r\n  color: var(--muted);\r\n  padding: .7rem .85rem;\r\n  border-radius: 8px;\r\n  cursor: pointer;\r\n  text-align: left;\r\n  font-size: .88rem;\r\n  width: 100%;\r\n}\r\n\r\n.nav-item:hover { background: var(--surface-2); color: var(--text); }\r\n.nav-item.active { background: rgba(0,230,118,.1); color: var(--green); font-weight: 600; }\r\n\r\n.back-link {\r\n  color: var(--muted);\r\n  font-size: .85rem;\r\n  text-decoration: none;\r\n  padding: .75rem;\r\n  margin-top: auto;\r\n}\r\n\r\n.main { padding: 1.5rem 2rem; overflow-y: auto; }\r\n\r\n.page-header {\r\n  display: flex;\r\n  justify-content: space-between;\r\n  align-items: flex-start;\r\n  margin-bottom: 1.25rem;\r\n  gap: 1rem;\r\n  flex-wrap: wrap;\r\n}\r\n\r\n.page-header > div:last-child,\r\n.page-header .header-actions {\r\n  display: flex;\r\n  gap: .5rem;\r\n  flex-wrap: wrap;\r\n}\r\n\r\n.page-header h1 { font-size: 1.4rem; }\r\n.page-header p { color: var(--muted); font-size: .9rem; margin-top: .2rem; }\r\n\r\n.stats-row {\r\n  display: grid;\r\n  grid-template-columns: repeat(4, 1fr);\r\n  gap: .75rem;\r\n  margin-bottom: 1.25rem;\r\n}\r\n\r\n.stat-card {\r\n  background: var(--surface);\r\n  border: 1px solid var(--border);\r\n  border-radius: var(--radius);\r\n  padding: 1rem;\r\n}\r\n\r\n.stat-card span { display: block; color: var(--muted); font-size: .8rem; }\r\n.stat-card strong { font-size: 1.6rem; margin-top: .2rem; display: block; }\r\n.stat-card.green strong { color: var(--green); }\r\n.stat-card.red strong { color: var(--red); }\r\n\r\n.card {\r\n  background: var(--surface);\r\n  border: 1px solid var(--border);\r\n  border-radius: var(--radius);\r\n  padding: 1rem;\r\n}\r\n\r\n.table-wrap { overflow-x: auto; }\r\n\r\ntable { width: 100%; border-collapse: collapse; font-size: .9rem; }\r\n\r\nth {\r\n  text-align: left;\r\n  padding: .75rem;\r\n  color: var(--muted);\r\n  font-size: .72rem;\r\n  text-transform: uppercase;\r\n  border-bottom: 1px solid var(--border);\r\n}\r\n\r\ntd {\r\n  padding: .85rem .75rem;\r\n  border-bottom: 1px solid var(--border);\r\n  vertical-align: middle;\r\n}\r\n\r\n.badge {\r\n  display: inline-block;\r\n  padding: .2rem .55rem;\r\n  border-radius: 999px;\r\n  font-size: .75rem;\r\n  font-weight: 600;\r\n}\r\n\r\n.badge.pending { background: rgba(245,158,11,.15); color: #f59e0b; }\r\n.badge.approved { background: rgba(0,230,118,.15); color: var(--green); }\r\n.badge.rejected { background: rgba(255,82,82,.15); color: var(--red); }\r\n.badge.semanal { background: rgba(79,140,255,.15); color: #4f8cff; }\r\n.badge.mensal { background: rgba(124,92,255,.15); color: #7c5cff; }\r\n.badge.diario { background: rgba(255,193,7,.15); color: #ffc107; }\r\n\r\n.actions { display: flex; gap: .4rem; flex-wrap: wrap; }\r\n\r\n.tool-btn, .btn-approve, .btn-reject, .btn-delete {\r\n  border: none;\r\n  border-radius: 8px;\r\n  padding: .45rem .75rem;\r\n  font-size: .8rem;\r\n  font-weight: 600;\r\n  cursor: pointer;\r\n}\r\n\r\n.tool-btn { background: var(--surface-2); color: var(--text); border: 1px solid var(--border); }\r\n.tool-btn.sound-on { border-color: rgba(0,230,118,.4); color: var(--green); }\r\n.tool-btn.sound-off { color: var(--muted); }\r\n.btn-approve { background: var(--green); color: #000; }\r\n.btn-reject { background: rgba(255,82,82,.2); color: var(--red); border: 1px solid rgba(255,82,82,.3); }\r\n.btn-delete { background: transparent; color: var(--muted); border: 1px solid var(--border); }\r\n\r\n.toast {\r\n  position: fixed;\r\n  bottom: 1.5rem;\r\n  right: 1.5rem;\r\n  background: var(--surface-2);\r\n  border: 1px solid var(--green);\r\n  padding: .85rem 1.25rem;\r\n  border-radius: 10px;\r\n  z-index: 200;\r\n}\r\n\r\n.empty-row td {\r\n  text-align: center;\r\n  color: var(--muted);\r\n  padding: 2.5rem;\r\n}\r\n\r\n@media (max-width: 768px) {\r\n  .layout { grid-template-columns: 1fr; }\r\n  .sidebar { display: none; }\r\n  .stats-row { grid-template-columns: 1fr 1fr; }\r\n  .plan-options, .plan-options-3 { grid-template-columns: 1fr; }\r\n}\r\n"
};
